// ============================================================================
// Line Slot (pooled rendering slot)
// ============================================================================

struct LineSlot {
    size_t line_number = 0;           // Which line is bound (0 = unbound)
    wchar_t text[ContentConfig::LINE_TEXT_BUFFER];  // UTF-16 text cache
    IDWriteTextLayout* layout = nullptr;
    float actual_width = 0.0f;        // Actual rendered width for h-scroll
    bool cache_valid = false;

    // Syntax highlighting spans for this line
    SyntaxSpan syntax_spans[Syntax::MAX_SPANS_PER_LINE];
    size_t syntax_span_count = 0;

    // Block comment continuation state for multi-line comments
    bool in_block_comment = false;

    LineSlot() { text[0] = L'\0'; }
};

